auto chain = Chain()
  .addLink(Link("validate", [](State& ctx) {
    if (ctx.get("input").empty())
      throw std::runtime_error("empty input");
    return ctx;
  }))
  .addLink(Link("process", [](State& ctx) {
    ctx.set("result", "done");
    return ctx;
  }));

State ctx;
ctx.set("input", "hello");
auto result = chain.execute(ctx);
